text:
@function get-color($key) {
  @if map-has-key($foundation-palette, $key) {
    @return map-get($foundation-palette, $key);
  }
  @else {
    @error 'given $key is not available in $foundation-palette';
  }
}

// Creates a wrapper for a series of columns
@mixin make-row($gutter: $grid-gutter-width) {
  margin-right: floor(math.div($gutter, -2));
  margin-left: ceil(math.div($gutter, -2));
  @include clearfix;
}

@mixin progress-bar-variant($color) {
  background-color: $color;

  // Deprecated parent class requirement as of v3.2.0
  .progress-striped & {
    @include gradient-striped;
  }
}

@mixin overflow-wrap($wrap: break-word) {
  word-wrap: $wrap;
  // stylelint-disable-next-line order/properties-alphabetical-order
  overflow-wrap: $wrap;
}

@mixin caret-down($width: $caret-width) {
  border-top: $width solid;
  border-right: $width solid transparent;
  border-bottom: 0;
  border-left: $width solid transparent;
}

@if $enable-reduced-motion and nth($transition, 1) != null and nth($transition, 1) != none {
  @media (prefers-reduced-motion: reduce) {
    transition: none;
  }
}

@mixin unselectable {
  -webkit-touch-callout: none;
  -webkit-user-select: none;
  -moz-user-select: none;
  -ms-user-select: none;
  user-select: none;
}

// Text truncate
// Requires inline-block or block for proper styling

@mixin text-truncate() {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

blockquote footer {
    margin-top: $base-blockquote-footer-margin-top;
    font-size: $base-blockquote-footer-font-size;
    line-height: $base-blockquote-footer-line-height;
    @if(meta.mixin-exists(hook-base-blockquote-footer)) {@include hook-base-blockquote-footer();}
}

// Colors
// Contextual variations (linked labels get darker on :hover)

.label-default {
  @include label-variant($label-default-bg);
}
